parameters.jsCode:
// Parse OpenAI response and merge with lead data
const lead   = $('📋 Parse Lead Data').first().json;
const rawAI  = $input.first().json.choices[0].message.content;

let ai = {};
try {
  // Strip any markdown fences
  const clean = rawAI.replace(/```(?:json)?/g, '').replace(/```/g, '').trim();
  ai = JSON.parse(clean);
} catch(e) {
  ai = {
    lead_score: 50,
    conversion_probability: 'Medium (50%)',
    intent: 'Unable to parse AI response',
    strategy: 'Manual review recommended',
    summary: rawAI.substring(0, 200),
    reply: 'Thank you for reaching out! We will be in touch shortly.',
  };
}

return [{
  json: {
    ...lead,
    lead_score:             ai.lead_score,
    conversion_probability: ai.conversion_probability,
    intent:   ai.intent,
    strategy: ai.strategy,
    summary:  ai.summary,
    reply:    ai.reply,
  }
}];

